  return fn(y: int) -> int { x + y };
}

// Lambdas (in filter, map, sort)
items.filter(fn(x: int) -> int { return x > 5; });
items.sort(fn(a: int, b: int) -> int { return a - b; });
```

## Control Flow

```mog
// If/else (also usable as expression)
if (x > 0) {
  println("positive");
} else if (x == 0) {
  println("zero");
} else {
  println("negative");
}

val := if (x > 0) { 1 } else { 0 };

// While
