```

## Error Handling

```mog
// Result<T>
fn divide(a: int, b: int) -> Result<int> {
  if (b == 0) {
    return err("division by zero");
  }
  return ok(a / b);
}

// Match on Result
match divide(10, 3) {
  ok(value) => println_i64(value),
  err(msg) => println(f"error: {msg}"),
}

// ? propagation (calling function must also return Result<T>)
fn calc() -> Result<int> {
  x := divide(10, 2)?;     // unwraps or propagates error
  return ok(x + 1);
}

// Try/catch
try {
  val := divide(10, 0)?;
} catch(e) {
  println(f"caught: {e}");
}

// Optional
fn find(items: [int], target: int) -> ?int {
  for i, v in items {
    if (v == target) {
      return some(i);
    }
  }
  return none;
}

match find(items, 42) {
  some(idx) => println_i64(idx),
  none => println("not found"),
}
```

