```mog
// math/lib.mog
package math;

pub fn add(a: int, b: int) -> int {
  return a + b;
}

fn helper() -> int {  // private to module
  return 42;
}

// main.mog
package main;
import math;

fn main() -> int {
  result := math.add(1, 2);
  return 0;
}
```

